sub register_user {
    my $username = param('username_reg');
    my $password = param('password_reg');

    unless ($username && $password) {
        print p(b('Error:'), ' Username and password are required for registration.');
        display_form();
        return;
    }

    $username =~ s/[^a-zA-Z0-9_.-]//g; # Basic sanitization
    if (length $username < 3 || length $username > 32) {
        print p(b('Error:'), ' Username must be between 3 and 32 characters.');
        display_form();
        return;
    }

    my %users = _read_users_db();

    if (exists $users{$username}) {
        print p(b('Error:'), " User '$username' already exists.");
    } else {
        my $hashed_password = md5_hex($password);
        _write_user_to_db($username, $hashed_password);
        print p(b('Success:'), " User '$username' registered successfully.");
    }
    display_form();
}

sub authenticate_user {
    my $username = param('username_auth');
    my $password = param('password_auth');

    unless ($username && $password) {
        print p(b('Error:'), ' Username and password are required for authentication.');
        display_form();
        return;
    }

    my %users = _read_users_db();

    if (exists $users{$username}) {
        my $stored_hashed_password = $users{$username};
        my $provided_hashed_password = md5_hex($password);

        if ($provided_hashed_password eq $stored_hashed_password) {
            print p(b('Success:'), " User '$username' authenticated successfully.");
        } else {
            print p(b('Error:'), ' Invalid password for user ', strong($username), '.');
        }
    } else {
        print p(b('Error:'), " User '$username' not found.");
    }
    display_form();
}

# --- Database Simulation Subroutines ---

# Reads user data from the flat file into a hash
sub _read_users_db {
    my %users;
    if (-e $USERS_DB_FILE) {
        open my $fh, '<', $USERS_DB_FILE or die "Cannot open $USERS_DB_FILE for reading: $!";
        flock $fh, LOCK_SH or die "Cannot get shared lock on $USERS_DB_FILE: $!";
        while (my $line = <$fh>) {
            chomp $line;
            my ($user, $hash) = split /:/, $line, 2;
            $users{$user} = $hash if defined $user && defined $hash;
        }
        close $fh;
    }
    return %users;
}

# Appends a new user to the flat file
sub _write_user_to_db {
    my ($username, $hashed_password) = @_;

    open my $fh, '>>', $USERS_DB_FILE or die "Cannot open $USERS_DB_FILE for writing: $!";
    flock $fh, LOCK_EX or die "Cannot get exclusive lock on $USERS_DB_FILE: $!";
    print $fh "$username:$hashed_password\n";
    close $fh;
}